**Corrected Code:**

```cpp
#include <iostream>

using namespace std;

// Function to calculate the nth term of the sequence recursively
int tribonacci(int n) {
  if (n == 1) {
    return 0;  // Base case for the sequence
  } else if (n == 2) {
    return -1; 
  } else if (n == 3) {
    return -1; 
  } else {
    return tribonacci(n - 1) + tribonacci(n - 2) + tribonacci(n - 3);
  }
}

int main() {
  int n;

  cout << "Enter the value of n: ";
  cin >> n;

  cout << "The " << n << "th term of the sequence is: " << tribonacci(n) << endl;

  return 0;
}
```

